sql:
SELECT player_id, points
FROM player_game_stats
ORDER BY points DESC;

SELECT T1.player_id, AVG(T1.games_missed) AS average_games_missed
FROM injuries AS T1
GROUP BY T1.player_id;

SELECT player_id, injury_type, games_missed
FROM injuries
ORDER BY games_missed DESC;
